INSERT INTO `venues` (`venue_id`, `manager_id`, `location_id`, `venue_name`, `capacity`, `description`, `suitable_themes`, `venue_type`, `ambiance`, `availability_status`, `image`, `status`, `created_at`) VALUES
(6, 2, 9, 'Sonya\'s Garden', 200, 'A charming garden venue nestled in Tagaytay with lush greenery, organic farm, and rustic-chic ambiance. Perfect for intimate weddings and garden parties with all-natural setting and fresh farm-to-table catering.', 'Wedding, Anniversary, Engagement, Birthday, Reunion', 'Garden', 'Rustic', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(7, 2, 10, 'Caleruega Church', 150, 'A stunning hilltop chapel and event venue overlooking Taal Lake. Features Mediterranean-inspired architecture, beautiful gardens, and breathtaking views. Ideal for weddings, christenings, and religious ceremonies.', 'Wedding, Christening, Anniversary, Engagement', 'Chapel & Garden', 'Elegant', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(8, 2, 16, 'Estancia Resort Hotel', 300, 'Elegant resort venue with panoramic Taal Lake views, spacious function rooms, and well-manicured gardens. Offers indoor and outdoor event spaces suitable for weddings, corporate events, and large celebrations.', 'Wedding, Corporate, Conference, Gala, Team Building', 'Resort', 'Elegant', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(9, 2, 9, 'Monte Vista Events Pavilion', 250, 'Modern event pavilion with floor-to-ceiling glass windows offering stunning Taal Volcano views. Features contemporary design, professional AV equipment, and climate-controlled spaces.', 'Wedding, Corporate, Conference, Product Launch, Seminar', 'Pavilion', 'Modern', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(10, 2, 7, 'Laguna Bel Air', 350, 'Premier resort and convention center featuring multiple function halls, outdoor gardens, and hot spring pools. Perfect for large-scale events, conferences, and weddings with complete amenities and accommodations.', 'Wedding, Corporate, Conference, Team Building, Reunion, Festival', 'Resort & Convention Center', 'Professional', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(11, 2, 6, 'Garden Pavilion at Paseo de Santa Rosa', 180, 'Elegant garden venue within a premier residential community. Features manicured lawns, modern pavilion, and excellent facilities. Ideal for sophisticated weddings and upscale events.', 'Wedding, Engagement, Anniversary, Cocktail Party, Gala', 'Garden Pavilion', 'Elegant', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(12, 2, 8, 'Villa Escudero Plantations and Resort', 400, 'Historic coconut plantation resort offering unique cultural experience with traditional Filipino ambiance. Features bamboo pavilions, museum, and waterfall restaurant. Perfect for cultural events and large gatherings.', 'Wedding, Cultural Event, Team Building, Reunion, Festival, Corporate', 'Heritage Resort', 'Cultural', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(13, 2, 17, 'The Gazebo Royale', 220, 'Beautiful garden venue with Victorian-inspired gazebos and romantic settings. Features landscaped gardens, koi ponds, and charming bridges. Perfect for romantic celebrations and themed events.', 'Wedding, Engagement, Anniversary, Birthday, Baby Shower', 'Garden', 'Romantic', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(14, 2, 11, 'Punta Fuego', 500, 'Exclusive beach and mountain club offering world-class facilities, private beach, championship golf course, and multiple event venues. Ideal for luxury weddings, corporate retreats, and high-end events.', 'Wedding, Corporate, Team Building, Gala, Product Launch, Conference', 'Beach Resort & Club', 'Luxurious', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(15, 2, 12, 'The Farm at San Benito', 180, 'Holistic wellness resort set in lush tropical rainforest. Offers unique vegan dining, eco-friendly facilities, and serene natural environment. Perfect for wellness retreats, intimate weddings, and mindful gatherings.', 'Wedding, Corporate, Team Building, Workshop, Retreat', 'Eco-Wellness Resort', 'Zen', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(17, 2, 19, 'Taal Vista Hotel', 400, 'Historic hotel with iconic Taal Lake and Volcano views. Offers grand ballrooms, manicured gardens, and professional event services. Perfect for weddings, conferences, and milestone celebrations.', 'Wedding, Corporate, Conference, Gala, Graduation, Anniversary', 'Historic Hotel', 'Classic', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(18, 2, 14, 'Arcadia Events Hall', 300, 'Modern event venue with contemporary design, state-of-the-art facilities, and ample parking. Features flexible spaces suitable for various events from corporate functions to social celebrations.', 'Wedding, Corporate, Conference, Seminar, Product Launch, Birthday', 'Events Hall', 'Modern', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(19, 2, 18, 'Marcia Adams Event Place', 200, 'Charming garden venue with Spanish-colonial inspired architecture. Features beautiful courtyard, vintage decor, and intimate settings. Perfect for romantic weddings and classic celebrations.', 'Wedding, Anniversary, Engagement, Birthday, Christening', 'Garden', 'Romantic', 'available', NULL, 'active', '2025-11-29 10:34:50'),
(20, 2, 15, 'Graceland Estates and Country Club', 350, 'Premier country club offering championship golf course, spacious function halls, and complete recreational facilities. Ideal for weddings, corporate events, and sports tournaments.', 'Wedding, Corporate, Team Building, Conference, Birthday, Reunion', 'Country Club', 'Professional', 'available', NULL, 'active', '2025-11-29 10:34:50');

